from collections import deque

class Solution:
    def invertTree(self, root):
        if not root:
            return None
        q = deque([root])
        while q:
            n = q.popleft()
            n.left, n.right = n.right, n.left
            if n.left:
                q.append(n.left)
            if n.right:
                q.append(n.right)
        return root

